import{_ as t,o as r,c as s,ai as n}from"./chunks/framework.Bke2s2V8.js";const m=JSON.parse('{"title":"Le présent - verbes réguliers","description":"","frontmatter":{},"headers":[],"relativePath":"module-2-construire-une-phrase/present-verbes-reguliers.md","filePath":"module-2-construire-une-phrase/present-verbes-reguliers.md","lastUpdated":1773303592000}'),d={name:"module-2-construire-une-phrase/present-verbes-reguliers.md"};function a(i,e,o,l,g,c){return r(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="le-present-verbes-reguliers" tabindex="-1">Le présent - verbes réguliers <a class="header-anchor" href="#le-present-verbes-reguliers" aria-label="Permalink to “Le présent - verbes réguliers”">​</a></h1><p><strong>Prérequis :</strong> <a href="./nominatif.html">Le nominatif</a></p><p><strong>Objectif :</strong> conjuguer n&#39;importe quel verbe régulier au présent en allemand.</p><p>Les verbes réguliers, appeles aussi &quot;verbes faibles&quot;, suivent tous le même modele. Une fois la règle connue, tu peux conjuguer des milliers de verbes sans les avoir jamais vus.</p><h2 id="la-methode-en-2-etapes" tabindex="-1">La methode en 2 etapes <a class="header-anchor" href="#la-methode-en-2-etapes" aria-label="Permalink to “La methode en 2 etapes”">​</a></h2><ol><li>Prendre l&#39;infinitif (la forme du dictionnaire, terminee par <strong>-en</strong>)</li><li>Enlever le <strong>-en</strong> pour obtenir le radical, puis ajouter la terminaison</li></ol><table tabindex="0"><thead><tr><th>Pronom</th><th>Terminaison</th><th>machen</th><th>lernen</th><th>wohnen</th></tr></thead><tbody><tr><td>ich</td><td><strong>-e</strong></td><td>mach<strong>e</strong></td><td>lern<strong>e</strong></td><td>wohn<strong>e</strong></td></tr><tr><td>du</td><td><strong>-st</strong></td><td>mach<strong>st</strong></td><td>lern<strong>st</strong></td><td>wohn<strong>st</strong></td></tr><tr><td>er/sie/es</td><td><strong>-t</strong></td><td>mach<strong>t</strong></td><td>lern<strong>t</strong></td><td>wohn<strong>t</strong></td></tr><tr><td>wir</td><td><strong>-en</strong></td><td>mach<strong>en</strong></td><td>lern<strong>en</strong></td><td>wohn<strong>en</strong></td></tr><tr><td>ihr</td><td><strong>-t</strong></td><td>mach<strong>t</strong></td><td>lern<strong>t</strong></td><td>wohn<strong>t</strong></td></tr><tr><td>sie/Sie</td><td><strong>-en</strong></td><td>mach<strong>en</strong></td><td>lern<strong>en</strong></td><td>wohn<strong>en</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Les terminaisons wir et sie/Sie sont identiques à l&#39;infinitif</p><p><em>wir machen</em> = nous faisons, <em>sie machen</em> = ils font / vous faites. La terminaison <em>-en</em> au pluriel est la même que l&#39;infinitif. C&#39;est pratique a retenir.</p></div><h2 id="cas-particulier-radical-en-t-ou-d" tabindex="-1">Cas particulier : radical en -t ou -d <a class="header-anchor" href="#cas-particulier-radical-en-t-ou-d" aria-label="Permalink to “Cas particulier : radical en -t ou -d”">​</a></h2><p>Quand le radical se termine par <strong>-t</strong> ou <strong>-d</strong>, on intercale un <strong>-e-</strong> devant la terminaison pour faciliter la prononciation. Cela concerne <em>du, er/sie/es</em> et <em>ihr</em>.</p><table tabindex="0"><thead><tr><th>Pronom</th><th>arbeiten (travailler)</th><th>warten (attendre)</th></tr></thead><tbody><tr><td>ich</td><td>arbeit<strong>e</strong></td><td>wart<strong>e</strong></td></tr><tr><td>du</td><td>arbeit<strong>e</strong>st</td><td>wart<strong>e</strong>st</td></tr><tr><td>er/sie/es</td><td>arbeit<strong>e</strong>t</td><td>wart<strong>e</strong>t</td></tr><tr><td>wir</td><td>arbeit<strong>en</strong></td><td>wart<strong>en</strong></td></tr><tr><td>ihr</td><td>arbeit<strong>e</strong>t</td><td>wart<strong>e</strong>t</td></tr><tr><td>sie/Sie</td><td>arbeit<strong>en</strong></td><td>wart<strong>en</strong></td></tr></tbody></table><h2 id="verbes-utiles-a-connaitre" tabindex="-1">Verbes utiles à connaître <a class="header-anchor" href="#verbes-utiles-a-connaitre" aria-label="Permalink to “Verbes utiles à connaître”">​</a></h2><div class="mt-4 grid grid-cols-2 gap-3"><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">machen</div><div class="text-sm text-gray-600">faire</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">lernen</div><div class="text-sm text-gray-600">apprendre</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">wohnen</div><div class="text-sm text-gray-600">habiter</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">spielen</div><div class="text-sm text-gray-600">jouer</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">kaufen</div><div class="text-sm text-gray-600">acheter</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">sagen</div><div class="text-sm text-gray-600">dire</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">fragen</div><div class="text-sm text-gray-600">demander</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">horen</div><div class="text-sm text-gray-600">entendre / ecouter</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">suchen</div><div class="text-sm text-gray-600">chercher</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">arbeiten</div><div class="text-sm text-gray-600">travailler</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">reisen</div><div class="text-sm text-gray-600">voyager</div></div><div class="p-3 rounded-lg border border-gray-200"><div class="font-semibold text-green-600">kochen</div><div class="text-sm text-gray-600">cuisiner</div></div></div><h2 id="exemples-en-phrases" tabindex="-1">Exemples en phrases <a class="header-anchor" href="#exemples-en-phrases" aria-label="Permalink to “Exemples en phrases”">​</a></h2><ul><li><em>Ich lerne Deutsch.</em> - J&#39;apprends l&#39;allemand.</li><li><em>Du wohnst in Paris.</em> - Tu habites a Paris.</li><li><em>Er kauft ein Buch.</em> - Il achete un livre.</li><li><em>Wir spielen Fußball.</em> - Nous jouons au football.</li><li><em>Ihr arbeitet viel.</em> - Vous travaillez beaucoup.</li><li><em>Sie reisen nach Berlin.</em> - Ils voyagent a Berlin.</li></ul><div class="info custom-block"><p class="custom-block-title">Le présent allemand couvre plusieurs sens français</p><p><em>Ich lerne Deutsch</em> peut se traduire par &quot;j&#39;apprends l&#39;allemand&quot;, &quot;je suis en train d&#39;apprendre l&#39;allemand&quot; ou &quot;j&#39;apprendrai l&#39;allemand (demain)&quot;. L&#39;allemand n&#39;a pas de forme progressive separee.</p></div>',16)])])}const v=t(d,[["render",a]]);export{m as __pageData,v as default};
